document.addEventListener("DOMContentLoaded",()=>{const a=document.querySelector(".site-name");if(!a){console.log(" target not found");return}let e=Math.random()*10,t=Math.random()*10,n=0;setInterval(()=>{e+=(Math.random()-.5)*1.2,t+=(Math.random()-.5)*1.2,n+=(Math.random()-.5)*.4,e=Math.max(-12,Math.min(12,e)),t=Math.max(-12,Math.min(12,t)),n=Math.max(-4,Math.min(4,n)),a.style.transform=`translate(${e}px, ${t}px) rotate(${n}deg)`},60);const r=document.querySelector(".site-avatar");if(!r){console.log(" target not found");return}let s=Math.random()*10,o=Math.random()*10,i=0;setInterval(()=>{s+=(Math.random()-.5)*1.2,o+=(Math.random()-.5)*1.2,i+=(Math.random()-.5)*.4,s=Math.max(-12,Math.min(12,s)),o=Math.max(-12,Math.min(12,o)),i=Math.max(-4,Math.min(4,i)),r.style.transform=`translate(${s}px, ${o}px) rotate(${i}deg)`},60)})